+  spdlog::info("  Port: {}", port);
+  spdlog::info("  Publish rate: {:.1f} Hz", publish_rate);
+  spdlog::info("  Session timeout: {:.1f} s", session_timeout);
+  if (!qos_profile.empty()) {
+    spdlog::info("  QoS profile: {}", qos_profile);
+  }
