 19→
 20→#include "pj_bridge_rti/dds_topic_discovery.hpp"
 21→
 22→#include <spdlog/spdlog.h>
 23→
 24→namespace pj_bridge {
 25→
 26→class DdsTopicDiscovery::PublisherListener
 27→    : public dds::sub::NoOpDataReaderListener<dds::topic::PublicationBuiltinTopicData> {
 28→ public:
 29→  PublisherListener(DdsTopicDiscovery& discovery, int32_t domain_id) : discovery_(discovery), domain_id_(domain_id) {}
 30→
 31→  void on_data_available(dds::sub::DataReader<dds::topic::PublicationBuiltinTopicData>& reader) override {
 32→    try {
 33→      auto samples = reader.select().state(dds::sub::status::DataState::new_instance()).take();
 34→
 35→      for (const auto& sample : samples) {
 36→        if (!sample.info().valid()) {
 37→          continue;
 38→        }
 39→
 40→        const auto& topic_name = sample.data().topic_name();
 41→        const auto& type = sample.data().extensions().type();
 42→
 43→        if (!type) {
 44→          spdlog::debug("Topic '{}' discovered without type info in domain {}", topic_name.to_std_string(), domain_id_);
 45→          continue;
 46→        }
 47→
 48→        const auto& type_name = type->name();
 49→
 50→        if (type->kind() != dds::core::xtypes::TypeKind::STRUCTURE_TYPE) {
 51→          spdlog::debug("Topic '{}' has non-struct type '{}', skipping", topic_name.to_std_string(), type_name);
 52→          continue;
 53→        }
 54→
 55→        auto struct_type = static_cast<const dds::core::xtypes::StructType&>(type.get());
 56→
 57→        rti::core::xtypes::DynamicTypePrintFormatProperty print_format{
 58→            0, false, rti::core::xtypes::DynamicTypePrintKind::idl, true};
 59→        std::string schema_idl = rti::core::xtypes::to_string(type.get(), print_format);
 60→
 61→        spdlog::info(
 62→            "Discovered topic '{}' (type: '{}') in domain {}", topic_name.to_std_string(), type_name, domain_id_);
 63→
 64→        discovery_.on_topic_discovered(topic_name.to_std_string(), type_name, struct_type, schema_idl, domain_id_);
 65→      }
 66→    } catch (const std::exception& e) {
 67→      spdlog::error("Exception in PublisherListener on domain {}: {}", domain_id_, e.what());
 68→    }
 69→  }
 70→
 71→ private:
 72→  DdsTopicDiscovery& discovery_;
 73→  int32_t domain_id_;
 74→};
 75→
 76→DdsTopicDiscovery::DdsTopicDiscovery(const std::vector<int32_t>& domain_ids, const std::string& qos_profile_path) {
 77→  if (!qos_profile_path.empty()) {
 78→    rti::core::QosProviderParams params;
 79→    params.url_profile({qos_profile_path});
 80→    rti::core::default_qos_provider_params(params);
 81→    spdlog::info("Set default QoS profile from '{}'", qos_profile_path);
 82→  }
 83→
 84→  for (int32_t domain_id : domain_ids) {
 85→    spdlog::info("Creating DomainParticipant for domain {}", domain_id);
 86→
 87→    dds::domain::DomainParticipant participant(domain_id);
 88→    participants_.emplace(domain_id, participant);
 89→
 90→    auto listener = std::make_shared<PublisherListener>(*this, domain_id);
 91→    listeners_.push_back(listener);
 92→
 93→    dds::sub::Subscriber builtin_subscriber = dds::sub::builtin_subscriber(participant);
 94→    std::vector<dds::sub::DataReader<dds::topic::PublicationBuiltinTopicData>> readers;
 95→    dds::sub::find<dds::sub::DataReader<dds::topic::PublicationBuiltinTopicData>>(
 96→        builtin_subscriber, dds::topic::publication_topic_name(), std::back_inserter(readers));
 97→
 98→    if (readers.empty()) {
 99→      spdlog::error("No built-in publication DataReader found for domain {}", domain_id);
100→      continue;
101→    }
102→
103→    readers[0].set_listener(listener);
104→    builtin_readers_.push_back(std::move(readers[0]));
105→
106→    spdlog::info("Topic discovery active on domain {}", domain_id);
107→  }
108→}
109→
110→DdsTopicDiscovery::~DdsTopicDiscovery() {
111→  spdlog::debug("[shutdown] ~DdsTopicDiscovery: clearing {} builtin readers", builtin_readers_.size());
112→  for (auto& reader : builtin_readers_) {
113→    try {
114→      reader.set_listener(nullptr);
115→    } catch (const std::exception& e) {
116→      spdlog::warn("Error clearing builtin reader listener: {}", e.what());
117→    } catch (...) {
118→      spdlog::warn("Unknown error clearing builtin reader listener");
119→    }
120→  }
121→  builtin_readers_.clear();
122→  listeners_.clear();
123→  spdlog::debug("[shutdown] ~DdsTopicDiscovery: builtin readers cleared");
124→
125→  for (auto& [domain_id, participant] : participants_) {
126→    try {
127→      spdlog::debug("[shutdown] Closing DomainParticipant for domain {}...", domain_id);
128→      participant.close();
129→      spdlog::debug("[shutdown] DomainParticipant for domain {} closed", domain_id);
130→    } catch (const std::exception& e) {
131→      spdlog::warn("Error closing participant for domain {}: {}", domain_id, e.what());
132→    } catch (...) {
133→      spdlog::warn("Unknown error closing participant for domain {}", domain_id);
134→    }
135→  }
136→  spdlog::debug("[shutdown] ~DdsTopicDiscovery complete");
137→}
138→
139→void DdsTopicDiscovery::on_topic_discovered(
140→    const std::string& topic_name, const std::string& type_name, const dds::core::xtypes::StructType& struct_type,
141→    const std::string& schema_idl, int32_t domain_id) {
142→  std::unique_lock<std::shared_mutex> lock(mutex_);
143→
144→  if (topics_.find(topic_name) != topics_.end()) {
145→    return;
146→  }
147→
148→  topics_.emplace(topic_name, DiscoveredTopic{type_name, struct_type, schema_idl, domain_id});
149→  spdlog::info("Cached topic '{}' (type: '{}', domain: {})", topic_name, type_name, domain_id);
150→}
151→
152→std::vector<DdsTopicInfo> DdsTopicDiscovery::get_topics() const {
153→  std::shared_lock<std::shared_mutex> lock(mutex_);
154→
155→  std::vector<DdsTopicInfo> result;
156→  result.reserve(topics_.size());
157→
158→  for (const auto& [name, topic] : topics_) {
159→    result.push_back({name, topic.type_name});
160→  }
161→
162→  return result;
163→}
164→
165→std::string DdsTopicDiscovery::get_schema(const std::string& topic_name) const {
166→  std::shared_lock<std::shared_mutex> lock(mutex_);
167→
168→  auto it = topics_.find(topic_name);
169→  if (it == topics_.end()) {
170→    return "";
171→  }
172→
173→  return it->second.schema_idl;
174→}
175→
176→std::optional<dds::core::xtypes::StructType> DdsTopicDiscovery::get_type(const std::string& topic_name) const {
177→  std::shared_lock<std::shared_mutex> lock(mutex_);
178→
179→  auto it = topics_.find(topic_name);
180→  if (it == topics_.end()) {
181→    return std::nullopt;
182→  }
183→
184→  return it->second.struct_type;
185→}
186→
187→std::optional<int32_t> DdsTopicDiscovery::get_domain_id(const std::string& topic_name) const {
188→  std::shared_lock<std::shared_mutex> lock(mutex_);
189→
190→  auto it = topics_.find(topic_name);
191→  if (it == topics_.end()) {
192→    return std::nullopt;
193→  }
194→
195→  return it->second.domain_id;
196→}
197→
198→dds::domain::DomainParticipant DdsTopicDiscovery::get_participant(int32_t domain_id) const {
199→  std::shared_lock<std::shared_mutex> lock(mutex_);
200→
201→  auto it = participants_.find(domain_id);
202→  if (it == participants_.end()) {
203→    throw std::runtime_error("No participant for domain " + std::to_string(domain_id));
204→  }
205→  return it->second;
206→}
