298→+class DdsSubscriptionManager::InternalReaderListener
299→+    : public dds::sub::NoOpDataReaderListener<dds::core::xtypes::DynamicData> {
300→+ public:
301→+  InternalReaderListener(const std::string& topic_name, DdsSubscriptionManager& manager)
302→+      : topic_name_(topic_name), manager_(manager) {}
303→+
304→+  void on_data_available(dds::sub::DataReader<dds::core::xtypes::DynamicData>& reader) override {
305→+    try {
306→+      auto samples = reader.take();
307→+
308→+      DdsMessageCallback cb;
309→+      {
310→+        std::lock_guard<std::mutex> lock(manager_.mutex_);
311→+        cb = manager_.callback_;
312→+      }
313→+
314→+      if (!cb) {
315→+        return;
316→+      }
317→+
318→+      for (const auto& sample : samples) {
319→+        if (!sample.info().valid()) {
320→+          continue;
321→+        }
322→+
323→+        auto cdr_buffer = sample.data().get_cdr_buffer();
324→+        const auto* raw_data = reinterpret_cast<const std::byte*>(cdr_buffer.first);
325→+        uint32_t data_size = cdr_buffer.second;
326→+
327→+        auto cdr_data = std::make_shared<std::vector<std::byte>>(raw_data, raw_data + data_size);
328→+
329→+        const auto& source_ts = sample.info().source_timestamp();
330→+        uint64_t timestamp_ns = (static_cast<uint64_t>(source_ts.sec()) * 1'000'000'000ULL) + source_ts.nanosec();
331→+
332→+        cb(topic_name_, std::move(cdr_data), timestamp_ns);
333→+      }
334→+    } catch (const std::exception& e) {
335→+      spdlog::error("Exception in DataReaderListener for '{}': {}", topic_name_, e.what());
336→+    }
337→+  }
338→+
339→+ private:
340→+  std::string topic_name_;
341→+  DdsSubscriptionManager& manager_;
342→+};
