355→+bool DdsSubscriptionManager::subscribe(const std::string& topic_name) {
356→+  std::lock_guard<std::mutex> lock(mutex_);
357→+
358→+  auto it = subscriptions_.find(topic_name);
359→+  if (it != subscriptions_.end()) {
360→+    it->second.reference_count++;
361→+    spdlog::debug("Incremented ref count for '{}' to {}", topic_name, it->second.reference_count);
362→+    return true;
363→+  }
364→+
365→+  auto struct_type_opt = discovery_.get_type(topic_name);
366→+  if (!struct_type_opt) {
367→+    spdlog::error("Topic '{}' not found in discovery", topic_name);
368→+    return false;
369→+  }
370→+
371→+  auto domain_id_opt = discovery_.get_domain_id(topic_name);
372→+  if (!domain_id_opt) {
373→+    spdlog::error("No domain ID for topic '{}'", topic_name);
374→+    return false;
375→+  }
376→+
377→+  auto& struct_type = *struct_type_opt;
378→+
379→+  try {
380→+    auto participant = discovery_.get_participant(*domain_id_opt);
381→+
382→+    rti::core::xtypes::DynamicDataTypeSerializationProperty ser_prop;
383→+    ser_prop.skip_deserialization(true);
384→+
385→+    rti::domain::register_type(participant, struct_type.name(), struct_type, ser_prop);
386→+
387→+    dds::topic::Topic<dds::core::xtypes::DynamicData> topic(participant, topic_name, struct_type.name());
388→+
389→+    dds::sub::Subscriber subscriber(participant);
390→+    dds::sub::DataReader<dds::core::xtypes::DynamicData> reader(subscriber, topic);
391→+
392→+    auto listener = std::make_shared<InternalReaderListener>(topic_name, *this);
393→+    reader.set_listener(listener);
394→+
395→+    subscriptions_.emplace(
396→+        std::piecewise_construct, std::forward_as_tuple(topic_name),
397→+        std::forward_as_tuple(subscriber, reader, listener, 1));
398→+
399→+    spdlog::info("Subscribed to '{}' (type: '{}', domain: {})", topic_name, struct_type.name(), *domain_id_opt);
400→+    return true;
401→+  } catch (const std::exception& e) {
402→+    spdlog::error("Failed to subscribe to '{}': {}", topic_name, e.what());
403→+    return false;
404→+  }
405→+}
406→+
407→+bool DdsSubscriptionManager::unsubscribe(const std::string& topic_name) {
408→+  std::optional<SubscriptionInfo> to_close;
409→+
410→+  {
411→+    std::lock_guard<std::mutex> lock(mutex_);
412→+
413→+    auto it = subscriptions_.find(topic_name);
414→+    if (it == subscriptions_.end()) {
415→+      return false;
416→+    }
417→+
418→+    if (it->second.reference_count == 0) {
419→+      return false;
420→+    }
421→+
422→+    it->second.reference_count--;
423→+    spdlog::debug("Decremented ref count for '{}' to {}", topic_name, it->second.reference_count);
424→+
425→+    if (it->second.reference_count == 0) {
426→+      to_close.emplace(std::move(it->second));
427→+      subscriptions_.erase(it);
428→+    }
429→+  }
430→+
431→+  if (to_close) {
432→+    try {
433→+      to_close->reader.set_listener(nullptr);
434→+      to_close->reader.close();
435→+      to_close->subscriber.close();
436→+    } catch (const std::exception& e) {
437→+      spdlog::warn("Error cleaning up reader for '{}': {}", topic_name, e.what());
438→+    } catch (...) {
439→+      spdlog::warn("Unknown error cleaning up reader for '{}'", topic_name);
440→+    }
441→+    spdlog::info("Unsubscribed from '{}' (reader destroyed)", topic_name);
442→+  }
443→+
444→+  return true;
445→+}
446→+
447→+size_t DdsSubscriptionManager::ref_count(const std::string& topic_name) const {
448→+  std::lock_guard<std::mutex> lock(mutex_);
449→+
450→+  auto it = subscriptions_.find(topic_name);
451→+  if (it != subscriptions_.end()) {
452→+    return it->second.reference_count;
453→+  }
454→+
455→+  return 0;
456→+}
457→+
458→+void DdsSubscriptionManager::unsubscribe_all() {
459→+  std::unordered_map<std::string, SubscriptionInfo> to_close;
460→+
461→+  {
462→+    std::lock_guard<std::mutex> lock(mutex_);
463→+    to_close.swap(subscriptions_);
464→+  }
465→+
466→+  spdlog::debug("[shutdown] unsubscribe_all: {} subscriptions to close", to_close.size());
467→+  for (auto& [name, info] : to_close) {
468→+    try {
469→+      spdlog::debug("[shutdown] Closing reader for '{}'...", name);
470→+      info.reader.set_listener(nullptr);
471→+      info.reader.close();
472→+      info.subscriber.close();
473→+      spdlog::debug("[shutdown] Closed '{}'", name);
474→+    } catch (const std::exception& e) {
475→+      spdlog::warn("Error cleaning up reader for '{}': {}", name, e.what());
476→+    } catch (...) {
477→+      spdlog::warn("Unknown error cleaning up reader for '{}'", name);
478→+    }
479→+  }
480→+  spdlog::debug("[shutdown] unsubscribe_all complete");
481→+}
482→+
483→+}  // namespace pj_bridge
