518→+  PublisherListener(DdsTopicDiscovery& discovery, int32_t domain_id) : discovery_(discovery), domain_id_(domain_id) {}
519→+
520→+  void on_data_available(dds::sub::DataReader<dds::topic::PublicationBuiltinTopicData>& reader) override {
521→+    try {
522→+      auto samples = reader.select().state(dds::sub::status::DataState::new_instance()).take();
523→+
524→+      for (const auto& sample : samples) {
525→+        if (!sample.info().valid()) {
526→+          continue;
527→+        }
528→+
529→+        const auto& topic_name = sample.data().topic_name();
530→+        const auto& type = sample.data().extensions().type();
531→+
532→+        if (!type) {
533→+          spdlog::debug("Topic '{}' discovered without type info in domain {}", topic_name.to_std_string(), domain_id_);
534→+          continue;
535→+        }
536→+
537→+        const auto& type_name = type->name();
538→+
539→+        if (type->kind() != dds::core::xtypes::TypeKind::STRUCTURE_TYPE) {
540→+          spdlog::debug("Topic '{}' has non-struct type '{}', skipping", topic_name.to_std_string(), type_name);
541→+          continue;
542→+        }
543→+
544→+        auto struct_type = static_cast<const dds::core::xtypes::StructType&>(type.get());
545→+
546→+        rti::core::xtypes::DynamicTypePrintFormatProperty print_format{
547→+            0, false, rti::core::xtypes::DynamicTypePrintKind::idl, true};
548→+        std::string schema_idl = rti::core::xtypes::to_string(type.get(), print_format);
549→+
550→+        spdlog::info(
551→+            "Discovered topic '{}' (type: '{}') in domain {}", topic_name.to_std_string(), type_name, domain_id_);
552→+
553→+        discovery_.on_topic_discovered(topic_name.to_std_string(), type_name, struct_type, schema_idl, domain_id_);
554→+      }
555→+    } catch (const std::exception& e) {
556→+      spdlog::error("Exception in PublisherListener on domain {}: {}", domain_id_, e.what());
557→+    }
558→+  }
559→+
560→+ private:
561→+  DdsTopicDiscovery& discovery_;
562→+  int32_t domain_id_;
563→+};
564→+
565→+DdsTopicDiscovery::DdsTopicDiscovery(const std::vector<int32_t>& domain_ids, const std::string& qos_profile_path) {
566→+  if (!qos_profile_path.empty()) {
567→+    rti::core::QosProviderParams params;
568→+    params.url_profile({qos_profile_path});
569→+    rti::core::default_qos_provider_params(params);
570→+    spdlog::info("Set default QoS profile from '{}'", qos_profile_path);
571→+  }
572→+
573→+  for (int32_t domain_id : domain_ids) {
574→+    spdlog::info("Creating DomainParticipant for domain {}", domain_id);
575→+
576→+    dds::domain::DomainParticipant participant(domain_id);
577→+    participants_.emplace(domain_id, participant);
578→+
579→+    auto listener = std::make_shared<PublisherListener>(*this, domain_id);
580→+    listeners_.push_back(listener);
581→+
582→+    dds::sub::Subscriber builtin_subscriber = dds::sub::builtin_subscriber(participant);
583→+    std::vector<dds::sub::DataReader<dds::topic::PublicationBuiltinTopicData>> readers;
584→+    dds::sub::find<dds::sub::DataReader<dds::topic::PublicationBuiltinTopicData>>(
585→+        builtin_subscriber, dds::topic::publication_topic_name(), std::back_inserter(readers));
586→+
587→+    if (readers.empty()) {
588→+      spdlog::error("No built-in publication DataReader found for domain {}", domain_id);
589→+      continue;
590→+    }
591→+
592→+    readers[0].set_listener(listener);
593→+    builtin_readers_.push_back(std::move(readers[0]));
594→+
595→+    spdlog::info("Topic discovery active on domain {}", domain_id);
596→+  }
597→+}
598→+
599→+DdsTopicDiscovery::~DdsTopicDiscovery() {
600→+  spdlog::debug("[shutdown] ~DdsTopicDiscovery: clearing {} builtin readers", builtin_readers_.size());
601→+  for (auto& reader : builtin_readers_) {
602→+    try {
603→+      reader.set_listener(nullptr);
604→+    } catch (const std::exception& e) {
605→+      spdlog::warn("Error clearing builtin reader listener: {}", e.what());
606→+    } catch (...) {
607→+      spdlog::warn("Unknown error clearing builtin reader listener");
608→+    }
609→+  }
610→+  builtin_readers_.clear();
611→+  listeners_.clear();
612→+  spdlog::debug("[shutdown] ~DdsTopicDiscovery: builtin readers cleared");
613→+
614→+  for (auto& [domain_id, participant] : participants_) {
615→+    try {
616→+      spdlog::debug("[shutdown] Closing DomainParticipant for domain {}...", domain_id);
617→+      participant.close();
618→+      spdlog::debug("[shutdown] DomainParticipant for domain {} closed", domain_id);
619→+    } catch (const std::exception& e) {
620→+      spdlog::warn("Error closing participant for domain {}: {}", domain_id, e.what());
621→+    } catch (...) {
622→+      spdlog::warn("Unknown error closing participant for domain {}", domain_id);
623→+    }
624→+  }
625→+  spdlog::debug("[shutdown] ~DdsTopicDiscovery complete");
626→+}
627→+
628→+void DdsTopicDiscovery::on_topic_discovered(
629→+    const std::string& topic_name, const std::string& type_name, const dds::core::xtypes::StructType& struct_type,
630→+    const std::string& schema_idl, int32_t domain_id) {
631→+  std::unique_lock<std::shared_mutex> lock(mutex_);
632→+
633→+  if (topics_.find(topic_name) != topics_.end()) {
634→+    return;
635→+  }
636→+
637→+  topics_.emplace(topic_name, DiscoveredTopic{type_name, struct_type, schema_idl, domain_id});
638→+  spdlog::info("Cached topic '{}' (type: '{}', domain: {})", topic_name, type_name, domain_id);
639→+}
640→+
641→+std::vector<DdsTopicInfo> DdsTopicDiscovery::get_topics() const {
642→+  std::shared_lock<std::shared_mutex> lock(mutex_);
643→+
644→+  std::vector<DdsTopicInfo> result;
645→+  result.reserve(topics_.size());
646→+
647→+  for (const auto& [name, topic] : topics_) {
648→+    result.push_back({name, topic.type_name});
649→+  }
650→+
651→+  return result;
652→+}
653→+
654→+std::string DdsTopicDiscovery::get_schema(const std::string& topic_name) const {
655→+  std::shared_lock<std::shared_mutex> lock(mutex_);
656→+
657→+  auto it = topics_.find(topic_name);
658→+  if (it == topics_.end()) {
659→+    return "";
660→+  }
661→+
662→+  return it->second.schema_idl;
663→+}
664→+
665→+std::optional<dds::core::xtypes::StructType> DdsTopicDiscovery::get_type(const std::string& topic_name) const {
666→+  std::shared_lock<std::shared_mutex> lock(mutex_);
667→+
668→+  auto it = topics_.find(topic_name);
669→+  if (it == topics_.end()) {
670→+    return std::nullopt;
671→+  }
672→+
673→+  return it->second.struct_type;
674→+}
675→+
676→+std::optional<int32_t> DdsTopicDiscovery::get_domain_id(const std::string& topic_name) const {
677→+  std::shared_lock<std::shared_mutex> lock(mutex_);
678→+
679→+  auto it = topics_.find(topic_name);
680→+  if (it == topics_.end()) {
681→+    return std::nullopt;
682→+  }
683→+
684→+  return it->second.domain_id;
685→+}
686→+
687→+dds::domain::DomainParticipant DdsTopicDiscovery::get_participant(int32_t domain_id) const {
688→+  std::shared_lock<std::shared_mutex> lock(mutex_);
689→+
690→+  auto it = participants_.find(domain_id);
691→+  if (it == participants_.end()) {
692→+    throw std::runtime_error("No participant for domain " + std::to_string(domain_id));
693→+  }
694→+  return it->second;
695→+}
696→+
697→+}  // namespace pj_bridge
