722→+
723→+#include <spdlog/spdlog.h>
724→+
725→+#include <CLI/CLI.hpp>
726→+#include <atomic>
727→+#include <chrono>
728→+#include <csignal>
729→+#include <string>
730→+#include <thread>
731→+#include <vector>
732→+
733→+#include "pj_bridge/bridge_server.hpp"
734→+#include "pj_bridge/middleware/websocket_middleware.hpp"
735→+#include "pj_bridge_rti/dds_subscription_manager.hpp"
736→+#include "pj_bridge_rti/dds_topic_discovery.hpp"
737→+#include "pj_bridge_rti/rti_subscription_manager.hpp"
738→+#include "pj_bridge_rti/rti_topic_source.hpp"
739→+
740→+namespace {
741→+std::atomic<bool> g_shutdown{false};
742→+
743→+void signal_handler(int /*signum*/) {
744→+  g_shutdown.store(true);
745→+}
746→+}  // namespace
747→+
748→+int main(int argc, char* argv[]) {
749→+  CLI::App app{"pj_bridge RTI DDS Backend"};
750→+
751→+  std::vector<int32_t> domain_ids;
752→+  int port = 8080;
753→+  double publish_rate = 50.0;
754→+  double session_timeout = 10.0;
755→+  std::string qos_profile;
756→+  std::string log_level = "info";
757→+  bool stats_enabled = false;
758→+
759→+  app.add_option("--domains,-d", domain_ids, "DDS domain IDs")->required()->expected(1, -1);
760→+  app.add_option("--port,-p", port, "WebSocket port")->default_val(8080)->check(CLI::Range(1, 65535));
761→+  app.add_option("--publish-rate", publish_rate, "Aggregation publish rate in Hz")->default_val(50.0);
762→+  app.add_option("--session-timeout", session_timeout, "Session timeout in seconds")->default_val(10.0);
763→+  app.add_option("--qos-profile", qos_profile, "QoS profile XML file path");
764→+  app.add_option("--log-level", log_level, "Log level (trace, debug, info, warn, error)")->default_val("info");
765→+  app.add_flag("--stats", stats_enabled, "Print statistics every 5 seconds");
766→+
767→+  CLI11_PARSE(app, argc, argv);
768→+
769→+  spdlog::set_level(spdlog::level::from_str(log_level));
770→+
771→+  spdlog::info("pj_bridge (RTI DDS backend) starting...");
772→+  spdlog::info("  Domains: {}", fmt::join(domain_ids, ", "));
773→+  spdlog::info("  Port: {}", port);
774→+  spdlog::info("  Publish rate: {:.1f} Hz", publish_rate);
775→+  spdlog::info("  Session timeout: {:.1f} s", session_timeout);
776→+  if (!qos_profile.empty()) {
777→+    spdlog::info("  QoS profile: {}", qos_profile);
778→+  }
779→+
780→+  std::signal(SIGINT, signal_handler);
781→+  std::signal(SIGTERM, signal_handler);
782→+
783→+  try {
784→+    // Create DDS components
785→+    pj_bridge::DdsTopicDiscovery discovery(domain_ids, qos_profile);
786→+    pj_bridge::DdsSubscriptionManager subscriptions(discovery);
787→+
788→+    // Create adapters
789→+    auto topic_source = std::make_shared<pj_bridge::RtiTopicSource>(discovery);
790→+    auto sub_manager = std::make_shared<pj_bridge::RtiSubscriptionManager>(subscriptions);
791→+
792→+    // Create WebSocket middleware
793→+    auto middleware = std::make_shared<pj_bridge::WebSocketMiddleware>();
794→+
795→+    // Create bridge server
796→+    pj_bridge::BridgeServer server(topic_source, sub_manager, middleware, port, session_timeout, publish_rate);
797→+
798→+    if (!server.initialize()) {
799→+      spdlog::error("Failed to initialize bridge server");
800→+      return 1;
801→+    }
802→+
803→+    spdlog::info("Bridge server initialized, entering event loop");
804→+
805→+    // Event loop
806→+    using clock = std::chrono::steady_clock;
807→+    auto publish_interval =
808→+        std::chrono::duration_cast<std::chrono::nanoseconds>(std::chrono::duration<double>(1.0 / publish_rate));
809→+    auto last_publish = clock::now();
810→+    auto last_timeout_check = clock::now();
811→+    auto last_stats_print = clock::now();
812→+    uint64_t prev_bytes_published = 0;
813→+
814→+    while (!g_shutdown.load()) {
815→+      server.process_requests();
816→+
817→+      auto now = clock::now();
818→+
819→+      if (now - last_publish >= publish_interval) {
820→+        server.publish_aggregated_messages();
821→+        last_publish += publish_interval;
822→+      }
823→+
824→+      if (now - last_timeout_check >= std::chrono::seconds(1)) {
825→+        server.check_session_timeouts();
826→+        last_timeout_check = now;
827→+      }
828→+
829→+      if (stats_enabled && now - last_stats_print >= std::chrono::seconds(5)) {
830→+        auto elapsed = std::chrono::duration<double>(now - last_stats_print).count();
831→+        auto snapshot = server.snapshot_and_reset_stats();
832→+
833→+        std::string stats_msg = "=== Stats ===\n  DDS receive rates:";
834→+        if (snapshot.topic_receive_counts.empty()) {
835→+          stats_msg += "\n    (no subscriptions)";
836→+        } else {
837→+          for (const auto& [topic, count] : snapshot.topic_receive_counts) {
838→+            stats_msg += fmt::format("\n    {}: {:.1f} msg/s", topic, static_cast<double>(count) / elapsed);
839→+          }
840→+        }
841→+
842→+        stats_msg +=
843→+            fmt::format("\n  Publish frequency: {:.1f} Hz", static_cast<double>(snapshot.publish_cycles) / elapsed);
844→+        uint64_t delta_bytes = snapshot.total_bytes_published - prev_bytes_published;
845→+        prev_bytes_published = snapshot.total_bytes_published;
846→+        stats_msg +=
847→+            fmt::format("\n  Sent: {:.2f} MB/s", static_cast<double>(delta_bytes) / elapsed / (1024.0 * 1024.0));
848→+
849→+        spdlog::info(stats_msg);
850→+        last_stats_print = now;
851→+      }
852→+
853→+      std::this_thread::sleep_for(std::chrono::milliseconds(1));
854→+    }
855→+
856→+    spdlog::info("Shutting down...");
857→+
858→+    // Explicit ordered shutdown to avoid use-after-free:
859→+    // 1. Clear DDS message callback
860→+    spdlog::debug("[shutdown] Clearing DDS message callback...");
861→+    subscriptions.set_message_callback(nullptr);
862→+    // 2. Unsubscribe all DDS readers
863→+    spdlog::debug("[shutdown] Unsubscribing all DDS readers...");
864→+    subscriptions.unsubscribe_all();
865→+    // 3. Shutdown WebSocket server
866→+    spdlog::debug("[shutdown] Shutting down WebSocket middleware...");
867→+    middleware->shutdown();
868→+    spdlog::debug("[shutdown] Cleanup complete, exiting scope (destructors will run)...");
869→+  } catch (const std::exception& e) {
870→+    spdlog::error("Fatal error: {}", e.what());
871→+    return 1;
872→+  }
873→+
874→+  return 0;
875→+}
