 25→
 26→GenericSubscriptionManager::GenericSubscriptionManager(rclcpp::Node::SharedPtr node) : node_(node) {}
 27→
 28→bool GenericSubscriptionManager::subscribe(
 29→    const std::string& topic_name, const std::string& topic_type, Ros2MessageCallback callback) {
 30→  std::lock_guard<std::mutex> lock(mutex_);
 31→
 32→  auto it = subscriptions_.find(topic_name);
 33→
 34→  if (it != subscriptions_.end()) {
 35→    it->second.reference_count++;
 36→    return true;
 37→  }
 38→
 39→  try {
 40→    auto sub_callback = [topic_name, callback](std::shared_ptr<rclcpp::SerializedMessage> msg) {
 41→      uint64_t receive_time = get_current_time_ns();
 42→      callback(topic_name, msg, receive_time);
 43→    };
 44→
 45→    auto subscription = node_->create_generic_subscription(topic_name, topic_type, rclcpp::QoS(100), sub_callback);
 46→
 47→    SubscriptionInfo info;
 48→    info.subscription = subscription;
 49→    info.topic_type = topic_type;
 50→    info.callback = callback;
 51→    info.reference_count = 1;
 52→
 53→    subscriptions_[topic_name] = std::move(info);
 54→
 55→    return true;
 56→  } catch (const std::exception& e) {
 57→    RCLCPP_ERROR(
 58→        node_->get_logger(), "Failed to create subscription for topic '%s' (type '%s'): %s", topic_name.c_str(),
 59→        topic_type.c_str(), e.what());
 60→    return false;
 61→  }
 62→}
 63→
 64→bool GenericSubscriptionManager::unsubscribe(const std::string& topic_name) {
 65→  std::lock_guard<std::mutex> lock(mutex_);
 66→
 67→  auto it = subscriptions_.find(topic_name);
 68→  if (it == subscriptions_.end()) {
 69→    return false;
 70→  }
 71→
 72→  if (it->second.reference_count == 0) {
 73→    return false;
 74→  }
 75→
 76→  it->second.reference_count--;
 77→
 78→  if (it->second.reference_count == 0) {
 79→    subscriptions_.erase(it);
 80→  }
 81→
 82→  return true;
 83→}
 84→
 85→bool GenericSubscriptionManager::is_subscribed(const std::string& topic_name) const {
 86→  std::lock_guard<std::mutex> lock(mutex_);
 87→  return subscriptions_.find(topic_name) != subscriptions_.end();
 88→}
 89→
 90→size_t GenericSubscriptionManager::get_reference_count(const std::string& topic_name) const {
 91→  std::lock_guard<std::mutex> lock(mutex_);
 92→
 93→  auto it = subscriptions_.find(topic_name);
 94→  if (it != subscriptions_.end()) {
 95→    return it->second.reference_count;
 96→  }
 97→
 98→  return 0;
 99→}
100→
101→void GenericSubscriptionManager::unsubscribe_all() {
102→  std::lock_guard<std::mutex> lock(mutex_);
103→  subscriptions_.clear();
104→}
