 20→#include <spdlog/spdlog.h>
 21→
 22→#include <CLI/CLI.hpp>
 23→#include <atomic>
 24→#include <chrono>
 25→#include <csignal>
 26→#include <string>
 27→#include <thread>
 28→#include <vector>
 29→
 30→#include "pj_bridge/bridge_server.hpp"
 31→#include "pj_bridge/middleware/websocket_middleware.hpp"
 32→#include "pj_bridge_rti/dds_subscription_manager.hpp"
 33→#include "pj_bridge_rti/dds_topic_discovery.hpp"
 34→#include "pj_bridge_rti/rti_subscription_manager.hpp"
 35→#include "pj_bridge_rti/rti_topic_source.hpp"
 36→
 37→namespace {
 38→std::atomic<bool> g_shutdown{false};
 39→
 40→void signal_handler(int /*signum*/) {
 41→  g_shutdown.store(true);
 42→}
 43→}  // namespace
 44→
 45→int main(int argc, char* argv[]) {
 46→  CLI::App app{"pj_bridge RTI DDS Backend"};
 47→
 48→  std::vector<int32_t> domain_ids;
 49→  int port = 8080;
 50→  double publish_rate = 50.0;
 51→  double session_timeout = 10.0;
 52→  std::string qos_profile;
 53→  std::string log_level = "info";
 54→  bool stats_enabled = false;
 55→
 56→  app.add_option("--domains,-d", domain_ids, "DDS domain IDs")->required()->expected(1, -1);
 57→  app.add_option("--port,-p", port, "WebSocket port")->default_val(8080)->check(CLI::Range(1, 65535));
 58→  app.add_option("--publish-rate", publish_rate, "Aggregation publish rate in Hz")->default_val(50.0);
 59→  app.add_option("--session-timeout", session_timeout, "Session timeout in seconds")->default_val(10.0);
 60→  app.add_option("--qos-profile", qos_profile, "QoS profile XML file path");
 61→  app.add_option("--log-level", log_level, "Log level (trace, debug, info, warn, error)")->default_val("info");
 62→  app.add_flag("--stats", stats_enabled, "Print statistics every 5 seconds");
 63→
 64→  CLI11_PARSE(app, argc, argv);
 65→
 66→  spdlog::set_level(spdlog::level::from_str(log_level));
 67→
 68→  spdlog::info("pj_bridge (RTI DDS backend) starting...");
 69→  spdlog::info("  Domains: {}", fmt::join(domain_ids, ", "));
 70→  spdlog::info("  Port: {}", port);
 71→  spdlog::info("  Publish rate: {:.1f} Hz", publish_rate);
 72→  spdlog::info("  Session timeout: {:.1f} s", session_timeout);
 73→  if (!qos_profile.empty()) {
 74→    spdlog::info("  QoS profile: {}", qos_profile);
 75→  }
 76→
 77→  std::signal(SIGINT, signal_handler);
 78→  std::signal(SIGTERM, signal_handler);
 79→
 80→  try {
 81→    // Create DDS components
 82→    pj_bridge::DdsTopicDiscovery discovery(domain_ids, qos_profile);
 83→    pj_bridge::DdsSubscriptionManager subscriptions(discovery);
 84→
 85→    // Create adapters
 86→    auto topic_source = std::make_shared<pj_bridge::RtiTopicSource>(discovery);
 87→    auto sub_manager = std::make_shared<pj_bridge::RtiSubscriptionManager>(subscriptions);
 88→
 89→    // Create WebSocket middleware
 90→    auto middleware = std::make_shared<pj_bridge::WebSocketMiddleware>();
 91→
 92→    // Create bridge server
 93→    pj_bridge::BridgeServer server(topic_source, sub_manager, middleware, port, session_timeout, publish_rate);
 94→
 95→    if (!server.initialize()) {
 96→      spdlog::error("Failed to initialize bridge server");
 97→      return 1;
 98→    }
 99→
100→    spdlog::info("Bridge server initialized, entering event loop");
101→
102→    // Event loop
103→    using clock = std::chrono::steady_clock;
104→    auto publish_interval =
105→        std::chrono::duration_cast<std::chrono::nanoseconds>(std::chrono::duration<double>(1.0 / publish_rate));
106→    auto last_publish = clock::now();
107→    auto last_timeout_check = clock::now();
108→    auto last_stats_print = clock::now();
109→    uint64_t prev_bytes_published = 0;
110→
111→    while (!g_shutdown.load()) {
112→      server.process_requests();
113→
114→      auto now = clock::now();
115→
116→      if (now - last_publish >= publish_interval) {
117→        server.publish_aggregated_messages();
118→        last_publish += publish_interval;
119→      }
120→
121→      if (now - last_timeout_check >= std::chrono::seconds(1)) {
122→        server.check_session_timeouts();
123→        last_timeout_check = now;
124→      }
125→
126→      if (stats_enabled && now - last_stats_print >= std::chrono::seconds(5)) {
127→        auto elapsed = std::chrono::duration<double>(now - last_stats_print).count();
128→        auto snapshot = server.snapshot_and_reset_stats();
129→
130→        std::string stats_msg = "=== Stats ===\n  DDS receive rates:";
131→        if (snapshot.topic_receive_counts.empty()) {
132→          stats_msg += "\n    (no subscriptions)";
133→        } else {
134→          for (const auto& [topic, count] : snapshot.topic_receive_counts) {
135→            stats_msg += fmt::format("\n    {}: {:.1f} msg/s", topic, static_cast<double>(count) / elapsed);
136→          }
137→        }
138→
139→        stats_msg +=
140→            fmt::format("\n  Publish frequency: {:.1f} Hz", static_cast<double>(snapshot.publish_cycles) / elapsed);
141→        uint64_t delta_bytes = snapshot.total_bytes_published - prev_bytes_published;
142→        prev_bytes_published = snapshot.total_bytes_published;
143→        stats_msg +=
144→            fmt::format("\n  Sent: {:.2f} MB/s", static_cast<double>(delta_bytes) / elapsed / (1024.0 * 1024.0));
145→
146→        spdlog::info(stats_msg);
147→        last_stats_print = now;
148→      }
149→
150→      std::this_thread::sleep_for(std::chrono::milliseconds(1));
151→    }
152→
153→    spdlog::info("Shutting down...");
154→
155→    // Explicit ordered shutdown to avoid use-after-free:
156→    // 1. Clear DDS message callback
157→    spdlog::debug("[shutdown] Clearing DDS message callback...");
158→    subscriptions.set_message_callback(nullptr);
159→    // 2. Unsubscribe all DDS readers
160→    spdlog::debug("[shutdown] Unsubscribing all DDS readers...");
161→    subscriptions.unsubscribe_all();
162→    // 3. Shutdown WebSocket server
163→    spdlog::debug("[shutdown] Shutting down WebSocket middleware...");
164→    middleware->shutdown();
165→    spdlog::debug("[shutdown] Cleanup complete, exiting scope (destructors will run)...");
166→  } catch (const std::exception& e) {
167→    spdlog::error("Fatal error: {}", e.what());
168→    return 1;
169→  }
170→
171→  return 0;
172→}
