38→class DdsTopicDiscovery {
39→ public:
40→  explicit DdsTopicDiscovery(const std::vector<int32_t>& domain_ids, const std::string& qos_profile_path = "");
41→  ~DdsTopicDiscovery();
42→
43→  DdsTopicDiscovery(const DdsTopicDiscovery&) = delete;
44→  DdsTopicDiscovery& operator=(const DdsTopicDiscovery&) = delete;
45→
46→  std::vector<DdsTopicInfo> get_topics() const;
47→  std::string get_schema(const std::string& topic_name) const;
48→  std::optional<dds::core::xtypes::StructType> get_type(const std::string& topic_name) const;
49→  std::optional<int32_t> get_domain_id(const std::string& topic_name) const;
50→  dds::domain::DomainParticipant get_participant(int32_t domain_id) const;
51→
52→ private:
53→  class PublisherListener;
54→
55→  struct DiscoveredTopic {
56→    std::string type_name;
57→    dds::core::xtypes::StructType struct_type;
58→    std::string schema_idl;
59→    int32_t domain_id;
60→
61→    DiscoveredTopic(const std::string& tn, const dds::core::xtypes::StructType& st, const std::string& idl, int32_t did)
62→        : type_name(tn), struct_type(st), schema_idl(idl), domain_id(did) {}
63→  };
64→
65→  void on_topic_discovered(
66→      const std::string& topic_name, const std::string& type_name, const dds::core::xtypes::StructType& struct_type,
67→      const std::string& schema_idl, int32_t domain_id);
68→
69→  mutable std::shared_mutex mutex_;
