#include "pj_bridge/protocol_constants.hpp"

namespace pj_bridge {

RtiTopicSource::RtiTopicSource(DdsTopicDiscovery& discovery) : discovery_(discovery) {}

std::vector<TopicInfo> RtiTopicSource::get_topics() {
  return discovery_.get_topics();
}

