 40→rclcpp::SerializedMessage strip_image(const rclcpp::SerializedMessage& input) {
 41→  rclcpp::Serialization<sensor_msgs::msg::Image> serializer;
 42→  sensor_msgs::msg::Image msg;
 43→  serializer.deserialize_message(&input, &msg);
 44→  msg.data = {0};
 45→  rclcpp::SerializedMessage output;
 46→  serializer.serialize_message(&msg, &output);
 47→  return output;
 48→}
 49→
 50→rclcpp::SerializedMessage strip_compressed_image(const rclcpp::SerializedMessage& input) {
 51→  rclcpp::Serialization<sensor_msgs::msg::CompressedImage> serializer;
 52→  sensor_msgs::msg::CompressedImage msg;
 53→  serializer.deserialize_message(&input, &msg);
 54→  msg.data = {0};
 55→  rclcpp::SerializedMessage output;
 56→  serializer.serialize_message(&msg, &output);
 57→  return output;
 58→}
 59→
 60→rclcpp::SerializedMessage strip_pointcloud2(const rclcpp::SerializedMessage& input) {
 61→  rclcpp::Serialization<sensor_msgs::msg::PointCloud2> serializer;
 62→  sensor_msgs::msg::PointCloud2 msg;
 63→  serializer.deserialize_message(&input, &msg);
 64→  msg.data = {0};
 65→  rclcpp::SerializedMessage output;
 66→  serializer.serialize_message(&msg, &output);
 67→  return output;
 68→}
 69→
 70→rclcpp::SerializedMessage strip_laser_scan(const rclcpp::SerializedMessage& input) {
 71→  rclcpp::Serialization<sensor_msgs::msg::LaserScan> serializer;
 72→  sensor_msgs::msg::LaserScan msg;
 73→  serializer.deserialize_message(&input, &msg);
 74→  msg.ranges = {0.0f};
 75→  msg.intensities = {0.0f};
 76→  rclcpp::SerializedMessage output;
 77→  serializer.serialize_message(&msg, &output);
 78→  return output;
 79→}
 80→
 81→rclcpp::SerializedMessage strip_occupancy_grid(const rclcpp::SerializedMessage& input) {
 82→  rclcpp::Serialization<nav_msgs::msg::OccupancyGrid> serializer;
 83→  nav_msgs::msg::OccupancyGrid msg;
 84→  serializer.deserialize_message(&input, &msg);
 85→  msg.data = {0};
 86→  rclcpp::SerializedMessage output;
 87→  serializer.serialize_message(&msg, &output);
 88→  return output;
 89→}
 90→
 91→}  // namespace
 92→
 93→bool MessageStripper::should_strip(const std::string& message_type) {
 94→  return kStrippableTypes.find(message_type) != kStrippableTypes.end();
 95→}
 96→
 97→rclcpp::SerializedMessage MessageStripper::strip(
 98→    const std::string& message_type, const rclcpp::SerializedMessage& input) {
 99→  if (message_type == "sensor_msgs/msg/Image") {
100→    return strip_image(input);
101→  }
102→  if (message_type == "sensor_msgs/msg/CompressedImage") {
103→    return strip_compressed_image(input);
104→  }
105→  if (message_type == "sensor_msgs/msg/PointCloud2") {
106→    return strip_pointcloud2(input);
107→  }
108→  if (message_type == "sensor_msgs/msg/LaserScan") {
109→    return strip_laser_scan(input);
110→  }
111→  if (message_type == "nav_msgs/msg/OccupancyGrid") {
112→    return strip_occupancy_grid(input);
113→  }
114→
115→  throw std::runtime_error("strip() not implemented for type: " + message_type);
116→}
