165→// Regression test for ref count corruption bug:
166→// The old code in handle_subscribe() called subscribe() BEFORE extracting the
167→// schema. If schema extraction failed, it would call unsubscribe() to undo the
168→// subscription. But if another client had already subscribed to the same topic,
169→// unsubscribe() would decrement the shared reference count, potentially causing
170→// message loss for the existing client.
171→//
172→// The fix moved schema extraction BEFORE subscribe(). This test verifies that
173→// the underlying mechanism is safe: subscribing twice (2 clients) then
174→// unsubscribing once (simulating the old error path) leaves the first client's
175→// subscription intact.
176→TEST_F(GenericSubscriptionManagerTest, SpuriousUnsubscribeDoesNotCorruptSharedRef) {
177→  auto callback = [](const std::string&, const std::shared_ptr<rclcpp::SerializedMessage>&, uint64_t) {};
178→
179→  // Client A subscribes
180→  ASSERT_TRUE(manager_->subscribe("/shared_topic", "std_msgs/msg/String", callback));
181→  EXPECT_EQ(manager_->get_reference_count("/shared_topic"), 1);
182→
183→  // Client B subscribes to the same topic (ref_count = 2)
184→  ASSERT_TRUE(manager_->subscribe("/shared_topic", "std_msgs/msg/String", callback));
185→  EXPECT_EQ(manager_->get_reference_count("/shared_topic"), 2);
186→
187→  // Simulate the old bug: client B's schema extraction fails, triggering unsubscribe
188→  EXPECT_TRUE(manager_->unsubscribe("/shared_topic"));
189→
190→  // Client A's subscription must still be alive
191→  EXPECT_TRUE(manager_->is_subscribed("/shared_topic"));
192→  EXPECT_EQ(manager_->get_reference_count("/shared_topic"), 1);
193→
194→  // Client A cleanly unsubscribes — subscription fully removed
195→  EXPECT_TRUE(manager_->unsubscribe("/shared_topic"));
196→  EXPECT_FALSE(manager_->is_subscribed("/shared_topic"));
197→  EXPECT_EQ(manager_->get_reference_count("/shared_topic"), 0);
198→}
