205→std::string remove_comments_from_schema(const std::string& schema) {
206→  std::istringstream input(schema);
207→  std::ostringstream output;
208→  std::string line;
209→
210→  while (std::getline(input, line)) {
211→    size_t comment_pos = line.find('#');
212→
213→    if (comment_pos != std::string::npos) {
214→      std::string before_comment = line.substr(0, comment_pos);
215→
216→      size_t end = before_comment.find_last_not_of(" \t\r\n");
217→      if (end != std::string::npos) {
218→        before_comment = before_comment.substr(0, end + 1);
219→      } else {
220→        before_comment = "";
221→      }
222→
223→      if (!before_comment.empty()) {
224→        output << before_comment << "\n";
225→      }
226→    } else {
227→      output << line << "\n";
228→    }
229→  }
230→
231→  return output.str();
232→}
