25→
26→std::vector<TopicInfo> TopicDiscovery::discover_topics() {
27→  topics_.clear();
28→
29→  auto topic_names_and_types = node_->get_topic_names_and_types();
30→
31→  for (const auto& [topic_name, topic_types] : topic_names_and_types) {
32→    if (should_filter_topic(topic_name)) {
33→      continue;
34→    }
35→
36→    if (!topic_types.empty()) {
37→      TopicInfo info;
38→      info.name = topic_name;
39→      info.type = topic_types[0];
40→      topics_.push_back(info);
41→    }
42→  }
43→
44→  return topics_;
45→}
