29→    : node_(node), inner_manager_(node), strip_large_messages_(strip_large_messages) {}
30→
31→void Ros2SubscriptionManager::set_message_callback(MessageCallback callback) {
32→  std::lock_guard<std::mutex> lock(callback_mutex_);
33→  callback_ = std::move(callback);
