36→bool Ros2SubscriptionManager::subscribe(const std::string& topic_name, const std::string& topic_type) {
37→  // Create a ROS2 callback that converts SerializedMessage → vector<byte> and calls the stored callback
38→  Ros2MessageCallback ros2_callback =
39→      [this, topic_type](
40→          const std::string& topic, const std::shared_ptr<rclcpp::SerializedMessage>& msg, uint64_t receive_time_ns) {
41→        // Optionally strip large fields
42→        const rclcpp::SerializedMessage* msg_to_use = msg.get();
43→        std::unique_ptr<rclcpp::SerializedMessage> stripped_msg;
44→
45→        if (strip_large_messages_ && MessageStripper::should_strip(topic_type)) {
46→          try {
47→            stripped_msg = std::make_unique<rclcpp::SerializedMessage>(MessageStripper::strip(topic_type, *msg));
48→            msg_to_use = stripped_msg.get();
49→          } catch (const std::exception& e) {
50→            spdlog::warn("Failed to strip message on topic '{}': {}. Forwarding original.", topic, e.what());
51→          }
52→        }
53→
54→        // Convert rclcpp::SerializedMessage to shared_ptr<vector<byte>>
55→        const auto& rcl_msg = msg_to_use->get_rcl_serialized_message();
56→        auto data = std::make_shared<std::vector<std::byte>>(rcl_msg.buffer_length);
57→        std::memcpy(data->data(), rcl_msg.buffer, rcl_msg.buffer_length);
58→
59→        // Invoke the stored callback
60→        MessageCallback cb;
61→        {
62→          std::lock_guard<std::mutex> lock(callback_mutex_);
63→          cb = callback_;
64→        }
65→        if (cb) {
66→          cb(topic, std::move(data), receive_time_ns);
67→        }
68→      };
69→
70→  return inner_manager_.subscribe(topic_name, topic_type, ros2_callback);
71→}
