 49→BridgeServer::~BridgeServer() {
 50→  // Shut down the middleware before members are destroyed so that
 51→  // disconnect callbacks (which capture `this`) cannot fire into
 52→  // a partially destroyed BridgeServer.
 53→  if (middleware_) {
 54→    middleware_->shutdown();
 55→  }
 56→}
