 58→bool BridgeServer::initialize() {
 59→  if (initialized_) {
 60→    spdlog::warn("Bridge server already initialized");
 61→    return true;
 62→  }
 63→
 64→  spdlog::info("Initializing bridge server...");
 65→
 66→  if (publish_rate_ <= 0.0) {
 67→    spdlog::error("Invalid publish_rate: {:.1f} (must be > 0)", publish_rate_);
 68→    return false;
 69→  }
 70→
 71→  message_buffer_ = std::make_shared<MessageBuffer>();
 72→  session_manager_ = std::make_unique<SessionManager>(session_timeout_);
 73→
 74→  spdlog::info("Core components created");
 75→
 76→  // Set the global message callback to feed into message buffer
 77→  subscription_manager_->set_message_callback(
 78→      [this](const std::string& topic_name, std::shared_ptr<std::vector<std::byte>> cdr_data, uint64_t timestamp_ns) {
 79→        {
 80→          std::lock_guard<std::mutex> lock(stats_mutex_);
 81→          topic_receive_counts_[topic_name]++;
 82→        }
 83→        if (message_buffer_) {
 84→          message_buffer_->add_message(topic_name, timestamp_ns, std::move(cdr_data));
 85→        }
 86→      });
 87→
 88→  // Register disconnect callback before middleware init to avoid missing events
 89→  middleware_->set_on_disconnect([this](const std::string& client_id) {
 90→    spdlog::info("Client disconnected: '{}'", client_id);
 91→    cleanup_session(client_id);
 92→  });
 93→
 94→  // Initialize middleware (may start accepting connections immediately)
 95→  auto result = middleware_->initialize(static_cast<uint16_t>(port_));
 96→  if (!result) {
 97→    spdlog::error("Failed to initialize middleware: {}", result.error());
 98→    return false;
 99→  }
100→  spdlog::info("Middleware initialized (port: {})", port_);
101→
102→  initialized_ = true;
103→  spdlog::info("Bridge server initialization complete");
104→
105→  return true;
106→}
107→
108→bool BridgeServer::process_requests() {
109→  if (!initialized_) {
110→    spdlog::error("Bridge server not initialized");
111→    return false;
112→  }
113→
114→  // Receive request (non-blocking with timeout)
115→  std::vector<uint8_t> request_data;
116→  std::string client_id;
117→  bool received = middleware_->receive_request(request_data, client_id);
118→
119→  if (!received || request_data.empty()) {
120→    return false;
121→  }
122→
123→  std::string request(request_data.begin(), request_data.end());
124→  if (client_id.empty()) {
125→    spdlog::warn("Received request with no client identity");
126→    return true;
127→  }
128→
129→  // Parse request JSON
130→  std::string response;
131→  json request_json;
132→  try {
133→    request_json = json::parse(request);
134→
135→    if (!request_json.contains("command")) {
136→      response = create_error_response("INVALID_REQUEST", "Missing 'command' field", request_json);
137→    } else {
138→      std::string command = request_json["command"];
139→
140→      spdlog::debug("Processing '{}' command from client '{}'", command, client_id);
141→
142→      if (command == "get_topics") {
143→        response = handle_get_topics(client_id, request_json);
144→      } else if (command == "subscribe") {
145→        response = handle_subscribe(client_id, request_json);
146→      } else if (command == "unsubscribe") {
147→        response = handle_unsubscribe(client_id, request_json);
148→      } else if (command == "heartbeat") {
149→        response = handle_heartbeat(client_id, request_json);
150→      } else if (command == "pause") {
151→        response = handle_pause(client_id, request_json);
152→      } else if (command == "resume") {
153→        response = handle_resume(client_id, request_json);
154→      } else {
155→        response = create_error_response("UNKNOWN_COMMAND", "Unknown command: " + command, request_json);
156→      }
157→    }
158→  } catch (const json::exception& e) {
159→    spdlog::error("JSON parse error: {}", e.what());
160→    response = create_error_response("INVALID_JSON", "Failed to parse JSON request", json::object());
161→  } catch (const std::exception& e) {
162→    spdlog::error("Error processing request: {}", e.what());
163→    response = create_error_response("INTERNAL_ERROR", "Internal server error", request_json);
164→  }
165→
166→  // Send response to the specific client
167→  std::vector<uint8_t> response_data(response.begin(), response.end());
168→  if (!middleware_->send_reply(client_id, response_data)) {
169→    spdlog::warn("Failed to send response to client '{}', cleaning up session", client_id);
170→    cleanup_session(client_id);
171→  }
172→  return true;
173→}
